const express = require('express');
const mongoose = require('mongoose');

const app = express();

// MongoDB connection setup
mongoose.connect('mongodb://localhost:27017/mydatabase', { useNewUrlParser: true, useUnifiedTopology: true });

// Example Mongoose model
const User = mongoose.model('User', new mongoose.Schema({
  name: String,
  age: Number,
  password: String,
  createdAt: Date
}));

// Query builder function
async function queryBuilder(filter = {}, projection = {}, sort = {}) {
  try {
    const results = await User.find(filter, projection).sort(sort);
    return results;
  } catch (error) {
    throw new Error('Error executing query: ' + error.message);
  }
}

// Example route using the query builder
app.get('/users', async (req, res) => {
  try {
    const filter = req.query.filter ? JSON.parse(req.query.filter) : {};
    const projection = req.query.projection ? JSON.parse(req.query.projection) : {};
    const sort = req.query.sort ? JSON.parse(req.query.sort) : {};

    const users = await queryBuilder(filter, projection, sort);
    res.json(users);
  } catch (error) {
    res.status(500).send(error.message);
  }
});

